import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { Container, Row, Col, Card, Form, Button, Alert } from 'react-bootstrap';
import { useAuth } from '../contexts/AuthContext';
import { LoginCredentials } from '../types';

export const Login: React.FC = () => {
  const [formData, setFormData] = useState<LoginCredentials>({
    correo: '',
    password: '',
  });
  const [showPassword, setShowPassword] = useState(false);
  const [validated, setValidated] = useState(false);
  const { login, isAuthenticated, loading, error } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();

  const from = location.state?.from?.pathname || '/';

  useEffect(() => {
    if (isAuthenticated) {
      navigate(from, { replace: true });
    }
  }, [isAuthenticated, navigate, from]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const form = e.currentTarget;

    if (form.checkValidity() === false) {
      e.stopPropagation();
      setValidated(true);
      return;
    }

    await login(formData);
  };

  const togglePassword = () => {
    setShowPassword(!showPassword);
  };

  return (
    <div style={{ 
      background: '#f0f0e8', 
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      padding: '30px'
    }}>
      <Container>
        <Row className="justify-content-center">
          <Col md={6} lg={4}>
            <Card className="border-0" style={{ 
              borderRadius: '16px',
              boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
              overflow: 'hidden'
            }}>
              <div style={{
                background: '#6B8E6B',
                padding: '30px',
                textAlign: 'center'
              }}>
                <div style={{
                  width: '60px',
                  height: '60px',
                  background: 'white',
                  borderRadius: '50%',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  margin: '0 auto 15px',
                  boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
                }}>
                  <i className="bi bi-person-circle" style={{ 
                    fontSize: '1.8rem', 
                    color: '#6B8E6B'
                  }}></i>
                </div>
                <h3 style={{ 
                  color: 'white', 
                  fontWeight: '600',
                  marginBottom: '5px',
                  fontSize: '1.5rem'
                }}>
                  Iniciar Sesion
                </h3>
                <p className="mb-0" style={{ 
                  color: 'rgba(255,255,255,0.9)',
                  fontSize: '0.9rem'
                }}>
                  Ingresa tus credenciales
                </p>
              </div>
              <Card.Body className="p-4">

                {error && (
                  <Alert variant="danger" className="mb-3" style={{ borderRadius: '8px' }}>
                    <i className="bi bi-exclamation-triangle me-2"></i> {error}
                  </Alert>
                )}

                <Form noValidate validated={validated} onSubmit={handleSubmit}>
                  <Form.Group className="mb-3" controlId="correo">
                    <Form.Label style={{ color: '#5a5a5a', fontWeight: '500', fontSize: '0.85rem' }}>
                      Correo Electronico
                    </Form.Label>
                    <Form.Control
                      type="email"
                      name="correo"
                      value={formData.correo}
                      onChange={handleChange}
                      placeholder="tu@email.com"
                      required
                      style={{ 
                        borderRadius: '8px', 
                        padding: '10px 14px',
                        border: '1px solid #d0d0d0',
                        fontSize: '0.9rem'
                      }}
                    />
                  </Form.Group>

                  <Form.Group className="mb-3" controlId="password">
                    <Form.Label style={{ color: '#5a5a5a', fontWeight: '500', fontSize: '0.85rem' }}>
                      Contrasena
                    </Form.Label>
                    <Form.Control
                      type={showPassword ? 'text' : 'password'}
                      name="password"
                      value={formData.password}
                      onChange={handleChange}
                      placeholder="Tu contrasena"
                      required
                      style={{ 
                        borderRadius: '8px', 
                        padding: '10px 14px',
                        border: '1px solid #d0d0d0',
                        fontSize: '0.9rem'
                      }}
                    />
                  </Form.Group>

                  <Form.Group className="mb-3" controlId="remember">
                    <Form.Check 
                      type="checkbox" 
                      label={<span style={{ fontSize: '0.85rem' }}>Recordarme</span>}
                    />
                  </Form.Group>

                  <Button 
                    variant="primary" 
                    type="submit" 
                    className="w-100 mb-3"
                    disabled={loading}
                    style={{
                      borderRadius: '8px',
                      padding: '12px',
                      fontWeight: '500',
                      background: '#6B8E6B',
                      border: 'none',
                      fontSize: '0.95rem'
                    }}
                  >
                    {loading ? (
                      <>
                        <span className="spinner-border spinner-border-sm me-2"></span>
                        Iniciando sesion...
                      </>
                    ) : (
                      <>Iniciar Sesion</>
                    )}
                  </Button>
                </Form>

                <div className="text-center pt-3" style={{ borderTop: '1px solid #e0e0e0' }}>
                  <p className="mb-2" style={{ color: '#888', fontSize: '0.85rem' }}>No tienes una cuenta?</p>
                  <Button 
                    variant="outline-secondary" 
                    href="/register"
                    className="w-100 mb-2"
                    style={{
                      borderRadius: '8px',
                      padding: '10px',
                      fontSize: '0.9rem',
                      border: '1px solid #d0d0d0'
                    }}
                  >
                    Crear Cuenta
                  </Button>
                </div>

                <div className="text-center mt-2">
                  <Link to="/recuperar" style={{ 
                    color: '#888', 
                    textDecoration: 'none',
                    fontSize: '0.8rem'
                  }}>
                    Olvidaste tu contrasena?
                  </Link>
                </div>
              </Card.Body>
            </Card>
          </Col>
        </Row>
      </Container>
    </div>
  );
};
